export function getAllVocabulary() {
  return week40.days.flatMap((day, dayIndex) =>
    (day.vocabulary || []).map((word, wordIndex) => ({
      ...word,
      id: `w40-d${dayIndex + 1}-${wordIndex}`,
      dayId: day.id,
      dayTitle: day.title,
    }))
  )
}
